   677→          {cameraError && <div>Camera: {cameraError}</div>}
   678→          {modelError && <div>Model: {modelError}</div>}
   679→        </div>
   680→      )}
   681→
   682→      {isModelLoading && (
   683→        <div
   684→          style={{
   685→            position: "absolute",
   686→            top: "50%",
   687→            left: "50%",
   688→            transform: "translate(-50%, -50%)",
   689→            color: "#fff",
   690→            fontSize: "1.5rem",
   691→            zIndex: 30,
   692→            pointerEvents: "none",
   693→          }}
   694→        >
   695→          Loading gesture recognition...
   696→        </div>
   697→      )}
   698→    </main>
   699→  );
   700→}
   701→
   702→/* ---------- Waiting Countdown ---------- */
   703→
   704→function WaitingCountdown() {
   705→  const [remaining, setRemaining] = useState(120);
   706→
   707→  useEffect(() => {
   708→    const timer = setInterval(() => {
   709→      setRemaining((s) => {
   710→        if (s <= 0) return 0;
   711→        return s - 1;
   712→      });
   713→    }, 1000);
   714→    return () => clearInterval(timer);
   715→  }, []);
   716→
   717→  const minutes = Math.floor(remaining / 60);
   718→  const seconds = remaining % 60;
   719→
   720→  return (
   721→    <p style={{ color: "rgba(255,255,255,0.3)", fontSize: "0.9rem", marginTop: 24 }}>
   722→      Auto-skip in {minutes}:{String(seconds).padStart(2, "0")}
   723→    </p>
   724→  );
   725→}
