     6→
     7→export type { MiraEmotion, MiraAvatarState };
     8→
     9→export interface UseMiraVideoAvatarReturn {
    10→  emotion: MiraEmotion;
    11→  avatarState: MiraAvatarState;
    12→  isSpeaking: boolean;
    13→  speak: (text: string, emotion?: MiraEmotion) => void;
    14→  setEmotion: (emotion: MiraEmotion) => void;
    15→  setAvatarState: (state: MiraAvatarState) => void;
    16→  stop: () => void;
    17→  startSession: () => void;
    18→  stopSession: () => void;
    19→  // For compatibility with existing code expecting orb-like interface
    20→  orbState: "idle" | "listening" | "thinking" | "speaking";
    21→  setOrbState: (state: "idle" | "listening" | "thinking" | "speaking") => void;
    22→}
    23→
    24→const API_URL = process.env.NEXT_PUBLIC_API_URL || "http://localhost:8000";
    25→
    26→/**
    27→ * Hook to manage Mira video avatar state and TTS playback.
    28→ * Replaces useOrbAvatar but uses video loops instead of the WebGL orb.
    29→ */
    30→export function useMiraVideoAvatar(): UseMiraVideoAvatarReturn {
    31→  const [emotion, setEmotionInternal] = useState<MiraEmotion>("idle");
    32→  const [avatarState, setAvatarStateInternal] = useState<MiraAvatarState>("idle");
    33→  const [isSpeaking, setIsSpeaking] = useState(false);
    34→  const [orbState, setOrbStateInternal] = useState<"idle" | "listening" | "thinking" | "speaking">("idle");
    35→
    36→  const ttsRef = useRef<StreamingTTS | null>(null);
    37→
    38→  const setEmotion = useCallback((newEmotion: MiraEmotion) => {
    39→    setEmotionInternal(newEmotion);
    40→  }, []);
    41→
    42→  const setAvatarState = useCallback((state: MiraAvatarState) => {
    43→    setAvatarStateInternal(state);
    44→  }, []);
    45→
    46→  // Map orbState to avatarState for backward compatibility
    47→  const setOrbState = useCallback((state: "idle" | "listening" | "thinking" | "speaking") => {
    48→    setOrbStateInternal(state);
    49→    
    50→    if (state === "speaking") {
    51→      setAvatarStateInternal("speaking");
    52→    } else if (state === "thinking") {
    53→      setEmotionInternal("thinking");
    54→      setAvatarStateInternal("idle");
    55→    } else {
    56→      setAvatarStateInternal("idle");
    57→    }
    58→  }, []);
    59→
    60→  const speak = useCallback(
    61→    (text: string, speakEmotion: MiraEmotion = "idle") => {
    62→      if (!text.trim() || !ttsRef.current) return;
    63→
    64→      // Set emotion and switch to speaking state
    65→      setEmotionInternal(speakEmotion);
    66→      setAvatarStateInternal("speaking");
    67→      setIsSpeaking(true);
    68→      setOrbStateInternal("speaking");
    69→
    70→      console.log(`[MiraVideoAvatar] Speaking (emotion=${speakEmotion}):`, text.slice(0, 80));
    71→
    72→      ttsRef.current
    73→        .speak(
    74→          text,
    75→          () => {
    76→            // onStart — audio playback has begun
    77→            console.log("[MiraVideoAvatar] Playback started");
    78→          },
    79→          () => {
    80→            // onEnd — audio playback finished
    81→            console.log("[MiraVideoAvatar] Playback finished");
    82→            setIsSpeaking(false);
    83→            setAvatarStateInternal("idle");
    84→            setOrbStateInternal("idle");
    85→            // Keep the emotion for a moment, then fade to idle
    86→            setTimeout(() => {
    87→              setEmotionInternal("idle");
    88→            }, 500);
    89→          }
    90→        )
    91→        .catch(() => {
    92→          setIsSpeaking(false);
    93→          setAvatarStateInternal("idle");
    94→          setEmotionInternal("idle");
    95→          setOrbStateInternal("idle");
    96→        });
    97→    },
    98→    []
    99→  );
   100→
   101→  const stop = useCallback(() => {
   102→    ttsRef.current?.stop();
   103→    setIsSpeaking(false);
   104→    setAvatarStateInternal("idle");
   105→    setEmotionInternal("idle");
   106→    setOrbStateInternal("idle");
   107→  }, []);
   108→
   109→  const startSession = useCallback(() => {
   110→    if (ttsRef.current) return;
   111→    const tts = new StreamingTTS(API_URL);
   112→    ttsRef.current = tts;
   113→    console.log("[MiraVideoAvatar] Session started");
   114→  }, []);
   115→
   116→  const stopSession = useCallback(() => {
   117→    ttsRef.current?.destroy();
   118→    ttsRef.current = null;
   119→    setIsSpeaking(false);
   120→    setAvatarStateInternal("idle");
   121→    setEmotionInternal("idle");
   122→    setOrbStateInternal("idle");
   123→    console.log("[MiraVideoAvatar] Session stopped");
   124→  }, []);
   125→
   126→  // Cleanup on unmount
   127→  useEffect(() => {
   128→    return () => {
   129→      ttsRef.current?.destroy();
   130→      ttsRef.current = null;
   131→    };
   132→  }, []);
   133→
   134→  return {
   135→    emotion,
   136→    avatarState,
   137→    isSpeaking,
   138→    speak,
   139→    setEmotion,
   140→    setAvatarState,
   141→    stop,
   142→    startSession,
   143→    stopSession,
   144→    // Backward compatibility
   145→    orbState,
   146→    setOrbState,
   147→  };
   148→}
