   702→/* ---------- Waiting Countdown ---------- */
   703→
   704→function WaitingCountdown() {
   705→  const [remaining, setRemaining] = useState(120);
   706→
   707→  useEffect(() => {
   708→    const timer = setInterval(() => {
   709→      setRemaining((s) => {
   710→        if (s <= 0) return 0;
   711→        return s - 1;
   712→      });
