   126→      queue: Array<{ id: string; user_id: string; name: string; position: number; status: string }>;
   127→    }) => {
   128→      console.log("[Mirror] queue_updated:", data);
   129→      if (kioskState === "session") return; // Don't interrupt active sessions
   130→
   131→      // During recap, store the update for when recap dismisses
   132→      if (kioskState === "recap") {
   133→        pendingQueueRef.current = data.active_user ?? null;
   134→        return;
   135→      }
   136→
   137→      if (data.active_user) {
   138→        setActiveUser(data.active_user);
   139→        setKioskState("waiting");
   140→      } else {
   141→        setActiveUser(null);
   142→        setKioskState("attract");
   143→      }
   144→    };
   145→
   146→    socket.on("queue_updated", handleQueueUpdated);
   147→    return () => {
   148→      socket.off("queue_updated", handleQueueUpdated);
   149→    };
   150→  }, [kioskState]);
   151→
   152→  // 2-minute timeout in waiting state
   153→  useEffect(() => {
   154→    if (kioskState === "waiting" && activeUser) {
   155→      waitingTimerRef.current = setTimeout(() => {
   156→        console.log("[Mirror] Waiting timeout — auto-skipping user");
   157→        skipQueueUser(activeUser.id).catch(() => {});
   158→      }, WAITING_TIMEOUT_MS);
   159→    }
   160→    return () => {
   161→      if (waitingTimerRef.current) {
   162→        clearTimeout(waitingTimerRef.current);
   163→        waitingTimerRef.current = null;
   164→      }
   165→    };
   166→  }, [kioskState, activeUser]);
   167→
   168→  // Listen for session_active from backend
   169→  useEffect(() => {
   170→    const handleSessionActive = () => {
   171→      setKioskState("session");
   172→      setSessionActive(true);
