   178→    };
   179→
   180→    socket.on("session_active", handleSessionActive);
   181→    return () => {
   182→      socket.off("session_active", handleSessionActive);
   183→    };
   184→    // eslint-disable-next-line react-hooks/exhaustive-deps
   185→  }, []);
   186→
   187→  // Listen for mira_speech events (streamed text from AI)
   188→  useEffect(() => {
   189→    const handleSpeech = (data: { text?: string; is_chunk?: boolean }) => {
   190→      // Fallback session detection
   191→      if (!sessionActive && !isStarting) {
   192→        setKioskState("session");
   193→        setSessionActive(true);
   194→        setIsStarting(false);
   195→        mira.startSession();
   196→        stt.startListening();
   197→      }
   198→
   199→      if (data.is_chunk !== false) {
   200→        if (!data.text) return;
   201→        console.log("[Mirror] mira_speech chunk received");
   202→        responseAccumulatorRef.current += data.text;
   203→        mira.setOrbState("thinking");
   204→        mira.setEmotion("thinking");
   205→      } else {
   206→        if (data.text) {
   207→          responseAccumulatorRef.current += data.text;
   208→        }
   209→        const fullText = responseAccumulatorRef.current;
   210→        responseAccumulatorRef.current = "";
   211→        console.log("[Mirror] Agent full response:", fullText);
   212→        if (!fullText) return;
   213→
   214→        // Parse emotion tag first, then detect from content as fallback
   215→        let { emotion, cleanText } = parseEmotionTag(fullText);
   216→
   217→        // If no explicit emotion tag, try to detect from content
   218→        if (emotion === "idle") {
