   220→        }
   221→
   222→        console.log("[Mirror] Parsed emotion:", emotion);
   223→        mira.speak(cleanText, emotion);
   224→      }
   225→    };
   226→
   227→    socket.on("mira_speech", handleSpeech);
   228→    return () => {
   229→      socket.off("mira_speech", handleSpeech);
   230→    };
   231→    // eslint-disable-next-line react-hooks/exhaustive-deps
   232→  }, [sessionActive, isStarting]);
   233→
   234→  // Listen for tool_result events (product recommendations + voice messages)
   235→  useEffect(() => {
   236→    const handleToolResult = (data: {
   237→      type?: string;
