   240→      text?: string;
   241→      emotion?: string;
   242→      outfit_name?: string;
   243→    }) => {
   244→      if (data.type === "display_product" && data.items) {
   245→        const clothingItems = mapToClothingItems(data.items);
   246→        const priceInfo: PriceStripItem[] = data.items.map((it) => ({
   247→          title: it.title,
   248→          price: it.price,
   249→        }));
   250→        if (clothingItems.length > 0) {
   251→          setCanvasOutfits((prev) => {
   252→            const next = [...prev, {
