   260→        }
   261→        return;
   262→      }
   263→      if (data.type === "voice_message" && data.text) {
   264→        const emotion = detectEmotionFromText(data.text);
   265→        mira.speak(data.text, emotion);
   266→        return;
   267→      }
   268→    };
   269→
   270→    socket.on("tool_result", handleToolResult);
   271→    return () => {
   272→      socket.off("tool_result", handleToolResult);
   273→    };
   274→    // eslint-disable-next-line react-hooks/exhaustive-deps
   275→  }, [mira.speak]);
   276→
   277→  // Listen for session_ended — show recap overlay, then return to attract
   278→  useEffect(() => {
   279→    const handleSessionEnded = (data?: {
   280→      summary?: string;
   281→      liked_items?: Array<{ title: string; price?: string; image_url?: string }>;
   282→      stats?: { items_shown: number; likes: number; dislikes: number };
   283→      user_name?: string;
   284→    }) => {
   285→      // Don't stop mira immediately — let closing speech TTS finish playing
   286→      stt.stopListening();
   287→      setSessionActive(false);
   288→      setCanvasOutfits([]);
