   299→        setKioskState("attract");
   300→      }
   301→    };
   302→
   303→    socket.on("session_ended", handleSessionEnded);
   304→    return () => {
   305→      socket.off("session_ended", handleSessionEnded);
   306→    };
   307→    // eslint-disable-next-line react-hooks/exhaustive-deps
   308→  }, []);
   309→
   310→  // Listen for session_force_end — same as session_ended
   311→  useEffect(() => {
